// The idempotent capture at the heart of the saga — the load-bearing detail
// that made async compensation safe.
async function capturePayment(orderId: string, idemKey: string, amount: Money) {
  const existing = await ledger.findByIdemKey(idemKey);
  if (existing) return existing; // safe retry: no double charge

  const capture = await psp.capture({ orderId, amount, idemKey });
  await ledger.record({ idemKey, orderId, captureId: capture.id, amount });
  await events.emit('payment.captured', { orderId, captureId: capture.id });
  return capture;
}
